namespace {
struct TrackValueBits {
  KnownBits computeKnownBits(Value *V, const DemandedBits &DB) {
    KnownBits Known(DB.getKnownZero(V), DB.getKnownOne(V));
    if (auto *And = dyn_cast<BinaryOperator>(V))
      if (And->getOpcode() == Instruction::And) {
        auto *Op1 = And->getOperand(0);
        auto *Op2C = And->getOperand(1);
        if (auto *Op2 = dyn_cast<ConstantInt>(Op2C)) {
          KnownBits Op1Known = computeKnownBits(Op1, DB);
          // If Op1 has known bits, we can propagate them through the AND.
          // The result can only have bits set where both operands have them.
          APInt Mask = Op2->getValue();
          Known.Zero = (~Mask) | Op1Known.Zero;
          Known.One = Op1Known.One & Mask;
        }
      }
    return Known;
  }
};
